```python
import requests
import json
from concurrent.futures import ThreadPoolExecutor, as_completed

# API端点配置
APIS = {
    'integrations': 'http://localhost:34913/config/integrations',
    'tickets': 'http://localhost:42171/helpdesk/tickets',
    'inventory': 'http://localhost:41575/inventory/products',
    'crm': 'http://localhost:43399/crm/customers',
    'kb': 'http://localhost:53747/kb/search',
    'scheduler': 'http://localhost:52615/scheduler/jobs'
}

# 各系统的查询参数
PARAMS = {
    'integrations': {},
    'tickets': {'status': 'all', 'limit': 100},
    'inventory': {'limit': 100},
    'crm': {'limit': 100},
    'kb': {'query': '*', 'max_results': 50},
    'scheduler': {'enabled': 'all'}
}

def call_api(name, url, params):
    try:
        resp = requests.post(url, json=params, timeout=30)
        return name, resp.status_code, resp.json() if resp.status_code == 200 else resp.text
    except Exception as e:
        return name, 'error', str(e)

results = {}
with ThreadPoolExecutor(max_workers=6) as executor:
    futures = {
        executor.submit(call_api, name, url, PARAMS[name]): name 
        for name, url in APIS.items()
    }
    for future in as_completed(futures):
        name, status, data = future.result()
        results[name] = {'status': status, 'data': data}
        print(f"[{name}] status={status}")

# 保存原始数据供后续分析
with open('/home/feic/pjs/SocialSystemArena/temp/weekly_ops_raw_data.json', 'w') as f:
    json.dump(results, f, indent=2, ensure_ascii=False)

print("\n=== API调用结果摘要 ===")
for name, r in results.items():
    print(f"{name}: HTTP {r['status']}")
    if isinstance(r['data'], dict):
        print(f"  - 返回字段: {list(r['data'].keys())[:5]}...")
    elif isinstance(r['data'], list):
        print(f"  - 返回数量: {len(r['data'])} items")
